-- Exercícios de Bíceps baseados nos GIFs do Supabase Storage
-- Total: 69 exercícios

ON CONFLICT (id) DO UPDATE SET 
    name = EXCLUDED.name,
    gif_path = EXCLUDED.gif_path,
    description = EXCLUDED.description,
    updated_at = NOW();

-- Verificar total de exercícios de bíceps
SELECT COUNT(*) as total_biceps FROM app_correcrat.exercises WHERE muscle_group_id = 'biceps';
